const doc = $input.first().json.documents[0];
const lat = parseFloat(doc.y);
const lon = parseFloat(doc.x);
const today = $now.toFormat('yyyy-MM-dd');

// 시도명 직접 추출
const sido = doc.address.region_1depth_name;

// 기상청 격자 변환 공식 (WGS84 → nx/ny)
const RE = 6371.00877;
const GRID = 5.0;
const SLAT1 = 30.0;
const SLAT2 = 60.0;
const OLON = 126.0;
const OLAT = 38.0;
const XO = 43;
const YO = 136;
const DEGRAD = Math.PI / 180.0;
const re = RE / GRID;
const slat1 = SLAT1 * DEGRAD;
const slat2 = SLAT2 * DEGRAD;
const olon = OLON * DEGRAD;
const olat = OLAT * DEGRAD;
let sn = Math.tan(Math.PI * 0.25 + slat2 * 0.5) / Math.tan(Math.PI * 0.25 + slat1 * 0.5);
sn = Math.log(Math.cos(slat1) / Math.cos(slat2)) / Math.log(sn);
let sf = Math.tan(Math.PI * 0.25 + slat1 * 0.5);
sf = Math.pow(sf, sn) * Math.cos(slat1) / sn;
let ro = Math.tan(Math.PI * 0.25 + olat * 0.5);
ro = re * sf / Math.pow(ro, sn);
const ra = Math.tan(Math.PI * 0.25 + lat * DEGRAD * 0.5);
const raVal = re * sf / Math.pow(ra, sn);
let theta = lon * DEGRAD - olon;
if (theta > Math.PI) theta -= 2.0 * Math.PI;
if (theta < -Math.PI) theta += 2.0 * Math.PI;
theta *= sn;
const nx = Math.floor(raVal * Math.sin(theta) + XO + 0.5);
const ny = Math.floor(ro - raVal * Math.cos(theta) + YO + 0.5);

// 날짜 형식 변환
const baseDate = today.replace(/-/g, '');

// 전날 날짜 계산
const yesterdayDate = new Date(today);
yesterdayDate.setDate(yesterdayDate.getDate() - 1);
const yesterday = yesterdayDate.getFullYear().toString() +
  String(yesterdayDate.getMonth() + 1).padStart(2, '0') +
  String(yesterdayDate.getDate()).padStart(2, '0');

// WGS84 → TM 좌표 변환
const toRad = d => d * Math.PI / 180;
const a = 6378137.0;
const f = 1 / 298.257222101;
const b = a * (1 - f);
const e2 = 1 - (b * b) / (a * a);
const e = Math.sqrt(e2);
const k0 = 1.0;
const lon0 = toRad(127.0028902777778);
const lat0 = toRad(38.0);
const FE = 200000.0;
const FN = 500000.0;
const latR = toRad(lat);
const lonR = toRad(lon);
const N = a / Math.sqrt(1 - e2 * Math.sin(latR) ** 2);
const T = Math.tan(latR) ** 2;
const C = (e2 / (1 - e2)) * Math.cos(latR) ** 2;
const A = Math.cos(latR) * (lonR - lon0);
const M = a * (
  (1 - e2/4 - 3*e2**2/64) * latR
  - (3*e2/8 + 3*e2**2/32) * Math.sin(2*latR)
  + (15*e2**2/256) * Math.sin(4*latR)
);
const M0 = a * (
  (1 - e2/4 - 3*e2**2/64) * lat0
  - (3*e2/8 + 3*e2**2/32) * Math.sin(2*lat0)
  + (15*e2**2/256) * Math.sin(4*lat0)
);
const tmX = FE + k0 * N * (A + (1-T+C)*A**3/6);
const tmY = FN + k0 * (M - M0 + N*Math.tan(latR)*(A**2/2 + (5-T+9*C)*A**4/24));

return [{
  nx,
  ny,
  baseDate,
  yesterday,
  lat,
  lon,
  sido,
  tmX: Math.round(tmX),
  tmY: Math.round(tmY)
}];

const all = $input.all();

// ── 최저/최고 기온 ───────────────────────────────────────────────────
const low_temperature  = all[0].json.low_temperature;
const high_temperature = all[0].json.high_temperature;

// ── 초단기실황 ──────────────────────────────────────────────────────
const realtimeRaw = all[1].json.response?.body?.items?.item;
const realtimeItems = Array.isArray(realtimeRaw) ? realtimeRaw : (realtimeRaw ? [realtimeRaw] : []);

const realtime = {};
realtimeItems.forEach(item => { realtime[item.category] = item.obsrValue; });

// ── 미세먼지 ────────────────────────────────────────────────────────
const dust = all[2].json.response?.body?.items?.[0];

// ── 코드 매핑 ────────────────────────────────────────────────────────
const skyCode  = { '1': '맑음', '3': '구름많음', '4': '흐림' };
const ptyCode  = { '0': '없음', '1': '비', '2': '비/눈', '3': '눈', '4': '소나기' };
const gradeMap = { '1': '좋음', '2': '보통', '3': '나쁨', '4': '매우나쁨' };

return [{
  temperature:     realtime['T1H']  ?? '알 수 없음',
  low_temperature,
  high_temperature,
  sky:             skyCode[realtime['SKY']] ?? '알 수 없음',
  rain:            ptyCode[realtime['PTY']] ?? '없음',
  humidity:        realtime['REH']  ?? '알 수 없음',
  windSpeed:       realtime['WSD']  ?? '알 수 없음',
  pm25:            dust?.pm25Value  ?? '알 수 없음',
  pm10:            dust?.pm10Value  ?? '알 수 없음',
  pm25_grade:      gradeMap[dust?.pm25Grade]  ?? '알 수 없음',
  pm10_grade:      gradeMap[dust?.pm10Grade]  ?? '알 수 없음',
}];

const items = $input.first().json.response?.body?.items?.item;
const forecastItems = Array.isArray(items) ? items : (items ? [items] : []);

// today를 input 데이터에서 직접 추출
const today = forecastItems[0]?.fcstDate;

let low_temperature  = '알 수 없음';
let high_temperature = '알 수 없음';

forecastItems.forEach(item => {
  if (item.fcstDate !== today) return;
  if (item.category === 'TMN') low_temperature  = item.fcstValue;
  if (item.category === 'TMX') high_temperature = item.fcstValue;
});

return [{ low_temperature, high_temperature }];

const restaurants = $input.all();
const ids = restaurants.map(r => r.json.id).filter(Boolean);
return [{ json: { restaurant_ids: ids, ids_str: ids.join(',') } }];

const restaurants = $('식당').all().map(r => r.json);
const menuItems = $('메뉴').all().map(m => m.json);

// restaurant_id 기준으로 메뉴 조인
const merged = restaurants.map(restaurant => ({
  ...restaurant,
  menus: menuItems.filter(menu => 
    menu.restaurant_id === restaurant.id && menu.is_available !== false
  )
}));

// 메뉴가 하나도 없는 가게 제외
const filtered = merged.filter(r => r.menus.length > 0);

return filtered.map(r => ({ json: r }));

const output = JSON.parse($('FoodRecommend').item.json.output);
const recommendations = output.recommendations;

return recommendations.map(r => ({ json: r }));
